      <!-- 레이더 그래프 -->
      <div class="radar-canvas-box">
        <canvas id="evalRadarChart"></canvas>
      </div>
      <!-- 5개 지표 근거 -->
      <div class="radar-legend-box" id="radarLegend"></div>
    </div>
  </div>
</div>
```

---

### 3. 레이더 그래프 JavaScript (Line 709~769)

**Chart.js radar 초기화 (Line 709~737):**
```js
const radarCtx = document.getElementById('evalRadarChart').getContext('2d');
new Chart(radarCtx, {
  type: 'radar',
  data: {
    labels: evalData.map(d => d.label),
    datasets: [{
      data: evalData.map(d => d.score),
      backgroundColor: 'rgba(44,74,124,0.15)',
      borderColor: '#2c4a7c',
      borderWidth: 2,
      pointBackgroundColor: '#2c4a7c',
      pointRadius: 3,
    }]
  },
  options: {
    responsive: true,
    maintainAspectRatio: true,
    plugins: { legend: { display: false } },
    scales: {
      r: {
        min: 0, max: 10,
        ticks: { stepSize: 2, font: { size: 9 }, backdropPadding: 2 },
        pointLabels: { font: { size: 10 }, color: '#333' },
        grid: { color: '#e0e3eb' },
        angleLines: { color: '#d0d5de' }
      }
    }
  }
});
```

**지표 근거 렌더링 (Line 740~754):**
```js
const box = document.getElementById('radarLegend');
const total = evalData.reduce((s, d) => s + d.score, 0);
evalData.forEach(d => {
  const pct = (d.score / 10 * 100).toFixed(0);
  const div = document.createElement('div');
  div.className = 'radar-item';
  div.innerHTML = `
    <div class="radar-item-header">
      <span class="r-label">${d.label}</span>
      <span class="r-score-badge">${d.score}/10</span>
    </div>
    <div class="r-score-bar"><div class="r-score-fill" style="width:${pct}%"></div></div>
    <div class="r-desc">${d.desc}</div>`;
  box.appendChild(div);
});
```

**총점/등급 처리 (Line 757~769):**
- `evalTotalScore` 엘리먼트에 총점 표시
- 45+ : 우수, 38+ : 양호, 28+ : 보통, 미만 : 미흡
- 등급별 배경색/글자색/테두리색 동적 적용
